## Database Integration with MongoDB

In modern web development, your API needs a reliable way to store and retrieve data. While in-memory storage works for temporary data, real applications require persistent storage that survives restarts and scales with user demand. This chapter introduces **MongoDB**—a leading NoSQL database—and **Mongoose**, a powerful Object Data Modeling (ODM) library for Node.js. By integrating MongoDB with your Express API, you’ll enable persistent data storage, structured schema validation, and efficient CRUD operations.

> 🔧 **Prerequisites**: Ensure you have Node.js and npm installed. You’ll also need a MongoDB Atlas account or a local MongoDB instance running.

---

## 1. Setting Up MongoDB with Mongoose

MongoDB is a document-oriented NoSQL database that stores data in flexible JSON-like documents (BSON format). It’s ideal for REST APIs due to its scalability, schema-less nature, and seamless integration with Node.js via Mongoose.

### Install Mongoose

From your project directory, install Mongoose:

```bash
npm install mongoose
```

### Connect to MongoDB

Create a new file `db.js` in your project (e.g., in a `config` folder):

```javascript
// config/db.js
const mongoose = require('mongoose');

const connectDB = async () => {
  try {
    const conn = await mongoose.connect(process.env.MONGO_URI || 'mongodb://localhost:27017/apiDB');
    console.log(`MongoDB Connected: ${conn.connection.host}`);
  } catch (error) {
    console.error(`Error connecting to MongoDB: ${error.message}`);
    process.exit(1); // Exit process with failure
  }
};

module.exports = connectDB;
```

> 💡 **Tip**: Use environment variables (via `dotenv`) for sensitive URIs. Create a `.env` file:
> ```
> MONGO_URI=mongodb+srv://<username>:<password>@cluster0.example.mongodb.net/apiDB?retryWrites=true&w=majority
> ```

Then, in your main app file (`app.js` or `server.js`), initialize the database connection:

```javascript
// app.js
require('dotenv').config();
const express = require('express');
const connectDB = require('./config/db');

const app = express();

// Connect to MongoDB
connectDB();

app.get('/', (req, res) => {
  res.send('API is running');
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

Now your API is connected to MongoDB. Every time the server starts, it will establish a connection to the database.

---

## 2. Designing Data Models with Mongoose

Mongoose allows you to define schemas with data types, validation, and middleware—bridging the gap between your application and MongoDB.

### What is a Mongoose Model?

A model is a constructor compiled from a schema. It represents a collection in MongoDB and provides methods to interact with documents.

### Example: Blog Post Model

Let’s create a model for a blog post.

```javascript
// models/Post.js
const mongoose = require('mongoose');

const postSchema = new mongoose.Schema({
  title: {
    type: String,
    required: [true, 'Title is required'],
    trim: true,
    maxlength: [100, 'Title cannot exceed 100 characters']
  },
  content: {
    type: String,
    required: true
  },
  author: {
    type: String,
    default: 'Admin'
  },
  createdAt: {
    type: Date,
    default: Date.now
  },
  tags: [String],
  isPublished: {
    type: Boolean,
    default: false
  }
});

// Add a static method
postSchema.statics.findByTag = function(tag) {
  return this.find({ tags: tag });
};

// Add a virtual for formatted date
postSchema.virtual('formattedDate').get(function() {
  return this.createdAt.toLocaleDateString('en-US');
});

module.exports = mongoose.model('Post', postSchema);
```

> ✅ **Schema Features Used**:
> - `type`: Defines data type.
> - `required`: Ensures field presence.
> - `trim`: Removes whitespace.
> - `maxlength`: Enforces string limits.
> - `default`: Sets fallback values.
> - `virtual`: Adds computed properties without storing in DB.
> - `statics`: Adds custom query methods.

---

## 3. Performing CRUD Operations

With your model in place, you can now perform full CRUD operations via your API routes.

### Create (POST)

```javascript
// routes/posts.js
const express = require('express');
const Post = require('../models/Post');
const router = express.Router();

// Create a new post
router.post('/', async (req, res) => {
  try {
    const post = await Post.create(req.body);
    res.status(201).json(post);
  } catch (error) {
    res.status(400).json({ message: error.message });
  }
});
```

> 📝 **Example Request**:
> ```http
> POST /posts
> Content-Type: application/json
> {
>   "title": "Getting Started with REST APIs",
>   "content": "Learn how to build RESTful services using Node.js and Express.",
>   "tags": ["nodejs", "backend", "api"]
> }
> ```
> ✅ **Response**:
> ```json
> {
>   "_id": "65d1234567890abcdef12345",
>   "title": "Getting Started with REST APIs",
>   "content": "...",
>   "author": "Admin",
>   "createdAt": "2024-04-15T10:00:00.000Z",
>   "tags": ["nodejs", "backend", "api"],
>   "isPublished": false,
>   "__v": 0
> }
> ```

---

### Read (GET)

Fetch all posts:

```javascript
// Get all posts
router.get('/', async (req, res) => {
  try {
    const posts = await Post.find().sort({ createdAt: -1 });
    res.json(posts);
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
});
```

Fetch a single post by ID:

```javascript
// Get a single post
router.get('/:id', async (req, res) => {
  try {
    const post = await Post.findById(req.params.id);
    if (!post) return res.status(404).json({ message: 'Post not found' });
    res.json(post);
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
});
```

Using the custom static method:

```javascript
// Get posts by tag
router.get('/tag/:tag', async (req, res) => {
  try {
    const posts = await Post.findByTag(req.params.tag);
    res.json(posts);
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
});
```

> 📝 **Example Request**:
> ```http
> GET /posts/tag/nodejs
> ```
> ✅ **Response**:
> ```json
> [
>   {
>     "_id": "65d1234567890abcdef12345",
>     "title": "Getting Started with REST APIs",
>     "content": "...",
>     "tags": ["nodejs", "backend"],
>     "formattedDate": "4/15/2024"
>   }
> ]
> ```

---

### Update (PUT/PATCH)

Update a post:

```javascript
// Update a post
router.put('/:id', async (req, res) => {
  try {
    const post = await Post.findByIdAndUpdate(
      req.params.id,
      req.body,
      { new: true, runValidators: true }
    );
    if (!post) return res.status(404).json({ message: 'Post not found' });
    res.json(post);
  } catch (error) {
    res.status(400).json({ message: error.message });
  }
});
```

---

### Delete (DELETE)

Delete a post:

```javascript
// Delete a post
router.delete('/:id', async (req, res) => {
  try {
    const post = await Post.findByIdAndDelete(req.params.id);
    if (!post) return res.status(404).json({ message: 'Post not found' });
    res.json({ message: 'Post deleted successfully' });
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
});
```

---

## 4. Best Practices and Tips

1. **Use Environment Variables**: Never hardcode credentials. Use `dotenv` to load `MONGO_URI`.
2. **Enable CORS**: If your frontend runs on a different port, enable CORS:
   ```bash
   npm install cors
   ```
   ```javascript
   const cors = require('cors');
   app.use(cors());
   ```
3. **Error Handling**: Centralize error handling using Express middleware.
4. **Validation**: Mongoose schema validation prevents invalid data from being stored.
5. **Connection Management**: Use `mongoose.connection.on('error')` to handle connection issues gracefully.

# **Chapter 5: Authentication and Authorization**

Building secure REST APIs requires robust authentication (verifying who a user is) and authorization (determining what a user can do). Without proper mechanisms, your API can be vulnerable to attacks like unauthorized data access, data breaches, or brute-force attacks.

In this chapter, we’ll explore three key approaches to securing your Node.js and Express APIs:
1. **JWT-based authentication** (stateless, scalable)
2. **Session and cookie-based authentication** (stateful, traditional)
3. **Role-based access control (RBAC)** (fine-grained permissions)

By the end, you’ll be able to implement secure authentication flows and restrict access based on user roles.

---

## **1. JWT-Based Authentication (Stateless & Scalable)**

JSON Web Tokens (JWT) are a popular choice for API authentication because they are **stateless**—meaning the server doesn’t need to store session data. Instead, the client sends a signed token with each request, and the server verifies it.

### **How JWT Works**
1. **User logs in** → Server validates credentials and generates a JWT.
2. **Client stores the JWT** (typically in `localStorage` or `cookies`).
3. **Client sends JWT in `Authorization` header** for subsequent requests.
4. **Server verifies the token** and grants access if valid.

### **Implementation Steps**

#### **1. Install Required Packages**
```bash
npm install jsonwebtoken bcryptjs dotenv
```
- `jsonwebtoken` → Generate and verify JWTs.
- `bcryptjs` → Hash passwords securely.
- `dotenv` → Load environment variables (for storing secrets).

#### **2. Create a JWT Utility**
Create a `utils/jwt.js` file to handle token generation and verification:

```javascript
const jwt = require('jsonwebtoken');
require('dotenv').config();

const generateToken = (userId) => {
  return jwt.sign({ id: userId }, process.env.JWT_SECRET, {
    expiresIn: '1h', // Token expires in 1 hour
  });
};

const verifyToken = (token) => {
  return jwt.verify(token, process.env.JWT_SECRET);
};

module.exports = { generateToken, verifyToken };
```

#### **3. Set Up Login Route**
In your `authController.js`:

```javascript
const { User } = require('../models');
const bcrypt = require('bcryptjs');
const { generateToken } = require('../utils/jwt');

const login = async (req, res) => {
  const { email, password } = req.body;

  // 1. Find user by email
  const user = await User.findOne({ where: { email } });
  if (!user) return res.status(401).json({ error: 'Invalid credentials' });

  // 2. Compare passwords
  const isMatch = await bcrypt.compare(password, user.password);
  if (!isMatch) return res.status(401).json({ error: 'Invalid credentials' });

  // 3. Generate JWT token
  const token = generateToken(user.id);

  res.json({ token });
};
```

#### **4. Protect Routes with Middleware**
Create a `middleware/auth.js` middleware to verify tokens:

```javascript
const { verifyToken } = require('../utils/jwt');

const authenticate = (req, res, next) => {
  // Get token from header (Bearer <token>)
  const token = req.header('Authorization')?.replace('Bearer ', '');
  if (!token) return res.status(401).json({ error: 'No token provided' });

  try {
    const decoded = verifyToken(token);
    req.userId = decoded.id; // Attach user ID to request
    next();
  } catch (err) {
    res.status(401).json({ error: 'Invalid token' });
  }
};

module.exports = authenticate;
```

#### **5. Apply Middleware to Protected Routes**
```javascript
const express = require('express');
const authenticate = require('../middleware/auth');
const router = express.Router();

// Protected route (only accessible with a valid JWT)
router.get('/profile', authenticate, (req, res) => {
  res.json({ userId: req.userId });
});

module.exports = router;
```

### **Example: JWT Flow in Action**
1. **User logs in:**
   ```http
   POST /api/auth/login
   Body: { "email": "user@example.com", "password": "secure123" }
   ```
   **Response:**
   ```json
   { "token": "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..." }
   ```

2. **User accesses a protected route:**
   ```http
   GET /api/profile
   Headers: { "Authorization": "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..." }
   ```
   **Response (if valid):**
   ```json
   { "userId": "123" }
   ```

